#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005;
ll t,n,a[N],num[70];
ll fun()
{
	ll x=0;
	for(int i=59;i>=0;i--)
	{
		if(!(x&((ll)1<<i)))
		{
			if(num[i])
			{
				x^=num[i];
			}
		}
	}
	return x;
}
bool check(ll x)
{
	for(int i=59;i>=0;i--)
	{
		if(x&((ll)1<<i))
		{
			if(num[i])
			{
				x^=num[i];
			}
			else return 0;
		}
	}
	return 1;
}
void insert(ll x)
{
	for(int j=59;j>=0;j--)
	{
		if(x&((ll)1<<j))
		{
			if(num[j])
			{
				x^=num[j];
			}
			else
			{
				num[j]=x;
				break; 
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout)
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		insert(a[i]);
	}
	cout<<fun();
	return 0;
}
